import numpy as np
from numba import njit, prange

@njit
def _power_iter(A, n_iter):
    n = A.shape[0]
    # Initialize with deterministic values
    x = np.empty(n, dtype=np.complex128)
    for i in range(n):
        x[i] = complex(float(i+1), float(n-i))

    norm_x = 0.0
    for i in range(n):
        norm_x += (x[i].real**2 + x[i].imag**2)
    norm_x = np.sqrt(norm_x)
    for i in range(n):
        x[i] /= norm_x

    for _ in range(n_iter):
        y = np.empty(n, dtype=np.complex128)
        for i in range(n):
            s = complex(0.0, 0.0)
            for j in range(n):
                s += complex(A[i,j], 0.0) * x[j]
            y[i] = s

        norm_y = 0.0
        for i in range(n):
            norm_y += (y[i].real**2 + y[i].imag**2)
        norm_y = np.sqrt(norm_y)

        lam = complex(0.0, 0.0)
        for i in range(n):
            lam += np.conj(x[i]) * y[i]

        for i in range(n):
            x[i] = y[i] / norm_y

    return lam, x

# Test correctness
